# Tests for `rgb_to_hex`

```python
import pytest

from mymodule import rgb_to_hex  # adjust import to your module


class TestRgbToHexHappyPath:
    """Tests for typical, valid inputs."""

    def test_pure_black(self):
        assert rgb_to_hex(0, 0, 0) == "#000000"

    def test_pure_white(self):
        assert rgb_to_hex(255, 255, 255) == "#ffffff"

    def test_pure_red(self):
        assert rgb_to_hex(255, 0, 0) == "#ff0000"

    def test_pure_green(self):
        assert rgb_to_hex(0, 255, 0) == "#00ff00"

    def test_pure_blue(self):
        assert rgb_to_hex(0, 0, 255) == "#0000ff"

    def test_arbitrary_color(self):
        assert rgb_to_hex(18, 52, 86) == "#123456"

    def test_mid_gray(self):
        assert rgb_to_hex(128, 128, 128) == "#808080"

    @pytest.mark.parametrize(
        "r,g,b,expected",
        [
            (171, 205, 239, "#abcdef"),
            (16, 32, 48, "#102030"),
            (1, 2, 3, "#010203"),
            (15, 15, 15, "#0f0f0f"),
            (100, 150, 200, "#6496c8"),
        ],
    )
    def test_various_colors(self, r, g, b, expected):
        assert rgb_to_hex(r, g, b) == expected


class TestRgbToHexEdgeCases:
    """Tests for boundary conditions and formatting details."""

    def test_returns_string(self):
        assert isinstance(rgb_to_hex(10, 20, 30), str)

    def test_starts_with_hash(self):
        assert rgb_to_hex(10, 20, 30).startswith("#")

    def test_total_length_is_seven(self):
        assert len(rgb_to_hex(10, 20, 30)) == 7

    def test_lowercase_output(self):
        result = rgb_to_hex(255, 171, 205)
        # everything after '#' should be lowercase
        assert result[1:] == result[1:].lower()

    def test_zero_padding_for_small_values(self):
        # ensures leading zeros are kept (e.g. 1 -> "01" not "1")
        assert rgb_to_hex(1, 2, 3) == "#010203"

    def test_lower_boundary(self):
        assert rgb_to_hex(0, 0, 0) == "#000000"

    def test_upper_boundary(self):
        assert rgb_to_hex(255, 255, 255) == "#ffffff"

    def test_mixed_boundaries(self):
        assert rgb_to_hex(0, 255, 0) == "#00ff00"
        assert rgb_to_hex(255, 0, 255) == "#ff00ff"

    def test_one_below_upper_boundary(self):
        assert rgb_to_hex(254, 254, 254) == "#fefefe"

    def test_one_above_lower_boundary(self):
        assert rgb_to_hex(1, 1, 1) == "#010101"


class TestRgbToHexErrorCases:
    """Tests for invalid inputs that should raise errors."""

    @pytest.mark.parametrize(
        "r,g,b",
        [
            (-1, 0, 0),
            (0, -1, 0),
            (0, 0, -1),
            (256, 0, 0),
            (0, 256, 0),
            (0, 0, 256),
            (-100, 50, 50),
            (300, 300, 300),
            (255, 255, 256),
            (-1, -1, -1),
        ],
    )
    def test_out_of_range_raises_value_error(self, r, g, b):
        with pytest.raises(ValueError, match="RGB values must be 0-255"):
            rgb_to_hex(r, g, b)

    def test_error_message_content(self):
        with pytest.raises(ValueError) as exc_info:
            rgb_to_hex(256, 0, 0)
        assert "0-255" in str(exc_info.value)

    def test_all_components_out_of_range(self):
        with pytest.raises(ValueError):
            rgb_to_hex(1000, -50, 999)

    def test_float_outside_range_raises(self):
        # Floats > 255 fail the bounds check before formatting
        with pytest.raises(ValueError):
            rgb_to_hex(255.5, 0, 0)

    def test_non_numeric_input_raises_type_error(self):
        # The comparison `0 <= c <= 255` against a string raises TypeError
        with pytest.raises(TypeError):
            rgb_to_hex("ff", 0, 0)

    def test_none_input_raises_type_error(self):
        with pytest.raises(TypeError):
            rgb_to_hex(None, 0, 0)

    def test_missing_argument_raises_type_error(self):
        with pytest.raises(TypeError):
            rgb_to_hex(0, 0)  # type: ignore[call-arg]

    def test_too_many_arguments_raises_type_error(self):
        with pytest.raises(TypeError):
            rgb_to_hex(0, 0, 0, 0)  # type: ignore[call-arg]
